#include<cstdio>
#include<cstdlib>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e7+10;
struct fhq{int l,r,siz;short key;char ch;}t[N];int Rt,cnt,T1,T2,T3;
inline int Node(char k){t[++cnt].ch=k;t[cnt].siz=1;t[cnt].key=rand();return cnt;}
inline void update(int k){t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;}
inline void split(int cur,int k,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	if(t[t[cur].l].siz>=k){y=cur;split(t[cur].l,k,x,t[cur].l);update(cur);return;}
	x=cur;split(t[cur].r,k-t[t[cur].l].siz-1,t[cur].r,y);update(cur);
}
inline int merge(int x,int y)
{
	if(!x||!y){return x|y;}
	if(t[x].key<t[y].key){t[x].r=merge(t[x].r,y);update(x);return x;}
	t[y].l=merge(x,t[y].l);update(y);return y;
}
inline int Ins(int rt,int n)
{
	char ch=getchar();rep(1,n,i)
	{
		if(ch<32||ch>126){--i;ch=getchar();continue;}
		rt=merge(rt,Node(ch));ch=getchar();
		
	}
	return rt;
}
inline char Get(){char ch;do ch=getchar();while(ch^'I'&&ch^'N'&&ch^'P'&&ch^'M'&&ch^'D'&&ch^'G');return ch;}
inline void pt(int cur){if(t[cur].l)pt(t[cur].l);putchar(t[cur].ch);if(t[cur].r)pt(t[cur].r);}
int main()
{
	srand(19260817);int Q=read(),cur=0;
	while(Q--)
	{
		char opt=Get();switch(opt)
		{
			case 'M':cur=read();break;case 'P':--cur;break;case 'N':++cur;break;
			case 'I':split(Rt,cur,T1,T2);Rt=merge(Ins(T1,read()),T2);break;
			case 'D':split(Rt,cur,T1,T2);split(T2,read(),T3,T2);Rt=merge(T1,T2);break;
			case 'G':split(Rt,cur,T1,T2);split(T2,read(),T2,T3);pt(T2);puts("");Rt=merge(merge(T1,T2),T3);
		}
	}
}
